<?php
namespace CargoDocsStudio\Database\Schema;
class ShipmentsTable extends AbstractTable { public function create(): void { global $wpdb; $table=$wpdb->prefix.'cds_shipments'; $collate=$wpdb->get_charset_collate(); $this->runSql("CREATE TABLE $table (id bigint unsigned NOT NULL AUTO_INCREMENT, tracking_code varchar(64) NOT NULL, token_hash char(64) NOT NULL, document_id bigint unsigned NULL, current_status varchar(64) NOT NULL DEFAULT 'Processing', current_location_text varchar(255) NULL, current_lat decimal(10,8) NULL, current_lng decimal(11,8) NULL, last_update_at datetime NULL, created_at datetime NOT NULL, PRIMARY KEY (id), UNIQUE KEY tracking_code (tracking_code), KEY token_hash (token_hash), KEY document_id (document_id), KEY last_update_at (last_update_at)) $collate;"); } }
